#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int R,G,B; scanf("%d %d %d",&R,&G,&B);
        if(R<B){
            printf("-1\n");
            continue;
        }
        int N = R+G+B;
        // colour string
        char *col = (char*)malloc(N+1);
        int idx=0;
        for(int i=0;i<G;i++) col[idx++]='G';
        for(int i=0;i<R;i++) col[idx++]='R';
        for(int i=0;i<B;i++) col[idx++]='B';
        col[N]='\0';
        printf("%s\n",col);
        // edges
        // green chain
        for(int i=2;i<=G;i++) printf("%d %d\n",i-1,i);
        int central = 1; // first green node
        // connect all red nodes to central green
        for(int i=1;i<=R;i++){
            int red_id = G + i;
            printf("%d %d\n",central,red_id);
        }
        // attach blue leaves to first B red nodes
        for(int i=1;i<=B;i++){
            int red_id = G + i;
            int blue_id = G + R + i;
            printf("%d %d\n",red_id,blue_id);
        }
        free(col);
    }
    return 0;
}

