import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            int R = Integer.parseInt(st.nextToken());
            int G = Integer.parseInt(st.nextToken());
            int B = Integer.parseInt(st.nextToken());
            if (R < B) {
                out.append("-1\n");
                continue;
            }
            int N = R + G + B;
            StringBuilder col = new StringBuilder(N);
            for (int i = 0; i < G; i++) col.append('G');
            for (int i = 0; i < R; i++) col.append('R');
            for (int i = 0; i < B; i++) col.append('B');
            out.append(col).append('\n');
            // green chain
            for (int i = 2; i <= G; i++) out.append(i-1).append(' ').append(i).append('\n');
            int central = 1; // first green node
            // connect all red nodes to central green
            for (int i = 1; i <= R; i++) {
                int redId = G + i;
                out.append(central).append(' ').append(redId).append('\n');
            }
            // attach blue leaves to first B red nodes
            for (int i = 1; i <= B; i++) {
                int redId = G + i;
                int blueId = G + R + i;
                out.append(redId).append(' ').append(blueId).append('\n');
            }
        }
        System.out.print(out.toString());
    }
}

